                // Forward the upstream response directly
                complete(response)
              case scala.util.Failure(exception) =>
                // Handle cases where the upstream request itself failed (e.g., connection error)
                val errorMessage = s"Failed to fetch content from $urlString: ${exception.getMessage}"
